function cleanStr(s) {
  return String(s || "")
    .replace(/\s+/g, " ")
    .replace(/^[\s,|]+|[\s,|]+$/g, "")
    .trim();
}

function splitCsv(str) {
  return cleanStr(str)
    .split(",")
    .map(s => s.trim())
    .filter(Boolean);
}

function normalizeUrl(u) {
  u = u.trim();
  if (!/^https?:\/\/www\./i.test(u)) {
    u = u.replace(/^https?:\/\//i, ""); // Remove existing protocol if any
    u = u.replace(/^www\./i, "");       // Remove existing www if any
    return "https://www." + u;
  }
  return u;
}

const input = items[0]?.json || {};
const rawUrls = cleanStr(input["Client URL"] || input["Client URLs"] || "");
const rawExclude = cleanStr(input["Keywords to be Excluded"] || "");

if (!rawUrls) {
  throw new Error("Client URL is required");
}

const urls = rawUrls
  .split(",")
  .map(s => normalizeUrl(s))
  .filter(Boolean);

let excludeGroups = [];
if (rawExclude.includes("|")) {
  excludeGroups = rawExclude
    .split("|")
    .map(g => splitCsv(g).map(t => t.toLowerCase()));
} else {
  excludeGroups = [splitCsv(rawExclude).map(t => t.toLowerCase())];
}

const perUrlExcludes = excludeGroups.length === urls.length
  ? excludeGroups
  : urls.map(() => excludeGroups[0] || []);

return urls.map((u, i) => ({
  json: {
    url: u,
    excludes: perUrlExcludes[i]
  }
}));

const input = items[0].json;

const rawQueryUrl = input.query_url;
const csv = input.data;

if (!rawQueryUrl) throw new Error("Missing query URL");
if (!csv) throw new Error("Missing CSV data");

function normalizePath(raw) {
  if (!raw) return null;
  let str = String(raw).trim()
    .replace(/^(https?:)?\/\//i, "") // remove http(s):// or //
    .replace(/^www\./i, "");         // remove leading www.

  const firstSlash = str.indexOf("/");
  let host = str;
  let path = "";
  if (firstSlash !== -1) {
    host = str.substring(0, firstSlash);
    path = str.substring(firstSlash);
  }
  path = path.replace(/\/+$/, ""); // strip trailing slash
  return host + path;
}

function parseCSV(text) {
  const lines = String(text).trim().split(/\r?\n/);
  const headers = lines[0].split(";").map(h => h.trim());
  return lines.slice(1).map(line => {
    const values = line.split(";").map(v => v.trim());
    const row = {};
    headers.forEach((h, i) => row[h] = values[i] || "");
    return row;
  });
}

const queryPath = normalizePath(rawQueryUrl);
if (!queryPath) throw new Error(`Invalid query URL after cleanup: ${rawQueryUrl}`);

const rows = parseCSV(csv);
const results = [];

for (const row of rows) {
  const rowPath = normalizePath(row.Url);
  if (!rowPath || rowPath !== queryPath) continue;

  const pos = parseInt(row.Position, 10);
  const vol = parseInt(row["Search Volume"], 10);
  const kd = Math.round(parseFloat(row["Keyword Difficulty"] || "0"));

  if (pos >= 5 && pos <= 15 && vol >= 500) {
    results.push({
      json: {
        keyword: row.Keyword,
        position: pos,
        volume: vol,
        kd,
        ranking_url: row.Url
      }
    });
  }
}

return results.length
  ? results.sort((a, b) => b.json.volume - a.json.volume).slice(0, 20)
  : [{
      json: {
        message: `No keywords matched for ${queryPath}`,
        note: "Exact host+path match required, Position 5–15, Volume ≥ 500"
      }
    }];

