// n8n Code Node for extracting top 3 URLs from SerpAPI results

// Get the input data from the previous node
const inputData = $input.all();

// Initialize output array
const outputItems = [];

// Process each input item
for (const item of inputData) {
  // Get the JSON data - adjust the path based on your actual data structure
  const serpApiData = item.json[0] || item.json;

  // Check if organic_results exists
  if (serpApiData && serpApiData.organic_results) {
    const organicResults = serpApiData.organic_results;

    // Get the keyword from search parameters
    const keyword = serpApiData.search_parameters?.q || 'unknown_keyword';

    // Get up to the first 3 results
    const topThree = organicResults.slice(0, 3);

    // Extract URL and position for each result
    topThree.forEach((r) => {
      outputItems.push({
        json: {
          keyword: keyword,
          competitor_url: r.link ?? r.url ?? null,
          competitor_title: r.title ?? null,
          competitor_position: r.position ?? null
        }
      });
    });
  } else {
    // If no organic_results found, return an error item
    outputItems.push({
      json: {
        keyword: 'error',
        competitor_url: null,
        competitor_title: null,
        competitor_position: null,
        error: 'No organic_results found in the data'
      }
    });
  }
}

// If no items were created, ensure at least one output
if (outputItems.length === 0) {
  outputItems.push({
    json: {
      keyword: 'error',
      competitor_url: null,
      competitor_title: null,
      competitor_position: null,
      error: 'No data processed'
    }
  });
}

// Return the processed items
return outputItems;

